namespace BlazorApp.Models;

public class EquipmentItem
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public DateTime LastInspected { get; set; }
}

using BlazorApp.Models;

namespace BlazorApp.Services;

public class EquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate network/database delay
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new() { Id = 1, Name = "Hydraulic Press A1", Location = "Building 3, Bay 7", LastInspected = new DateTime(2026, 4, 12) },
            new() { Id = 2, Name = "CNC Lathe B2", Location = "Building 1, Bay 2", LastInspected = new DateTime(2026, 5, 1) },
            new() { Id = 3, Name = "Overhead Crane #4", Location = "Building 3, Bay 1", LastInspected = new DateTime(2026, 3, 20) },
            new() { Id = 4, Name = "Welding Station C1", Location = "Building 2, Bay 5", LastInspected = new DateTime(2026, 5, 18) },
            new() { Id = 5, Name = "Forklift FL-09", Location = "Warehouse A", LastInspected = new DateTime(2026, 2, 28) },
            new() { Id = 6, Name = "Air Compressor #2", Location = "Building 1, Utility Room", LastInspected = new DateTime(2026, 4, 30) },
            new() { Id = 7, Name = "Band Saw D3", Location = "Building 2, Bay 3", LastInspected = new DateTime(2026, 5, 10) },
            new() { Id = 8, Name = "Conveyor Belt System", Location = "Building 3, Bay 4-6", LastInspected = new DateTime(2026, 1, 15) },
        };
    }
}

@page "/inventory"
@rendermode InteractiveServer
@using BlazorApp.Models
@using BlazorApp.Services
@inject EquipmentService EquipmentService
@inject PersistentComponentState ApplicationState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (equipment is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in equipment)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? equipment;
    private PersistingComponentStateSubscription persistingSubscription;

    protected override async Task OnInitializedAsync()
    {
        persistingSubscription = ApplicationState.RegisterOnPersisting(PersistData);

        if (ApplicationState.TryTakeFromJson<List<EquipmentItem>>("equipment", out var restored))
        {
            // Interactive circuit: reuse data persisted during prerender — no second fetch
            equipment = restored;
        }
        else
        {
            // Prerender pass: fetch from service (only call)
            equipment = await EquipmentService.GetEquipmentAsync();
        }
    }

    private Task PersistData()
    {
        ApplicationState.PersistAsJson("equipment", equipment);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        persistingSubscription.Dispose();
    }
}

